// --- KOMPONENT AKORDEONU (BEZ FRAMER MOTION - CZYSTY REACT) ---
function AccordionItem({ title, paragraphs }: { title: string, paragraphs: string[] }) {
  const [isOpen, setIsOpen] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);

  // Styl gradientu dla zwiniętego kafelka
  const gradientStyle = {
    background: 'linear-gradient(135deg, #0071E3 0%, #00C7BE 100%)',
    color: 'white',
  };

  // Styl dla rozwiniętego kafelka (biały)
  const openStyle = {
    background: 'white',
    color: '#1D1D1F',
    border: '1px solid #e5e5e5'
  };

  return (
    <div 
      onClick={() => setIsOpen(!isOpen)}
      style={{
        borderRadius: '24px',
        marginBottom: '16px',
        cursor: 'pointer',
        boxShadow: '0 4px 20px rgba(0,0,0,0.05)',
        transition: 'all 0.3s ease',
        overflow: 'hidden',
        ...(isOpen ? openStyle : gradientStyle)
      }}
    >
      {/* NAGŁÓWEK */}
      <div style={{ 
        padding: '24px', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        gap: '15px'
      }}>
        <h3 style={{ 
          fontSize: '1.1rem', 
          fontWeight: 700, 
          margin: 0,
          lineHeight: 1.4
        }}>
          {title}
        </h3>
        
        {/* IKONA */}
        <div style={{
          transition: 'transform 0.3s ease',
          transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)',
          flexShrink: 0
        }}>
          {isOpen ? <ChevronUp size={24} /> : <ChevronDown size={24} />}
        </div>
      </div>

      {/* TREŚĆ (ANIMACJA CSS HEIGHT) */}
      <div 
        ref={contentRef}
        style={{
          height: isOpen ? contentRef.current?.scrollHeight : 0,
          opacity: isOpen ? 1 : 0,
          transition: 'height 0.3s ease, opacity 0.3s ease',
          overflow: 'hidden'
        }}
      >
        <div style={{ padding: '0 24px 24px 24px', color: '#424245', lineHeight: '1.6' }}>
          {paragraphs.map((p, i) => (
            <p key={i} style={{ marginBottom: '12px', fontSize: '0.95rem' }}>{p}</p>
          ))}
        </div>
      </div>
    </div>
  );
}

